// listAlertResponse is a helper struct for scanning ListAlert query results
// from PostgreSQL columns. The db tags match the aliases generated by
// selectQueryField from the search field labels (case-insensitive).
// Fields that may be NULL (e.g. entity-specific fields like namespace_id,
// deployment_id, node_id) use pointer types to handle NULL scanning.
type listAlertResponse struct {
	ID                 string     `db:"alert_id"`
	LifecycleStage     *int       `db:"lifecycle_stage"`
	Time               *time.Time `db:"violation_time"`
	State              *int       `db:"violation_state"`
	PolicyID           *string    `db:"policy_id"`
	PolicyName         *string    `db:"policy"`
	Severity           *int       `db:"severity"`
	Description        *string    `db:"description"`
	Categories         []string   `db:"category"`
	EnforcementAction  *int       `db:"enforcement_action"`
	EnforcementCount   *int       `db:"enforcement_count"`
	EntityType         *int       `db:"entity_type"`
	ClusterID          *string    `db:"cluster_id"`
	ClusterName        *string    `db:"cluster"`
	Namespace          *string    `db:"namespace"`
	NamespaceID        *string    `db:"namespace_id"`
	DeploymentID       *string    `db:"deployment_id"`
	DeploymentName     *string    `db:"deployment"`
	DeploymentType     *string    `db:"deployment_type"`
	DeploymentInactive *bool      `db:"inactive_deployment"`
	NodeID             *string    `db:"node_id"`
	NodeName           *string    `db:"node"`
	ResourceName       *string    `db:"resource"`
	ResourceType       *int       `db:"resource_type"`
}

func (r *listAlertResponse) GetLifecycleStage() storage.LifecycleStage {
	if r.LifecycleStage == nil {
		return 0
	}
	return storage.LifecycleStage(*r.LifecycleStage)
}

